-- Seed/update default salary components from the HRMS salary template.
-- No schema change. Existing PayrollSetups.SetupJson is updated in-place.

USE payroll;

SET @salaryComponents = '[{"id":101,"code":"BASIC","componentType":"Basic","category":"Earning","name":"Basic","payType":"Fixed Pay","calculationType":"Formula","value":"","formula":"GROSS * 50%","baseComponent":"GROSS","taxable":true,"ctc":true,"proRata":true,"fbp":false,"restrictFbp":false,"epf":"Always","esi":true,"recurring":true,"scheduled":false,"investmentType":"","correctionOf":"","active":true,"priority":"10"},{"id":102,"code":"HRA","componentType":"House Rent Allowance","category":"Earning","name":"HRA","payType":"Fixed Pay","calculationType":"Formula","value":"","formula":"BASIC * 40%","baseComponent":"BASIC","taxable":true,"ctc":true,"proRata":true,"fbp":false,"restrictFbp":false,"epf":"Never","esi":true,"recurring":true,"scheduled":false,"investmentType":"","correctionOf":"","active":true,"priority":"20"},{"id":103,"code":"TEL_ALLOW","componentType":"Telephone","category":"Earning","name":"Telephonic Allowance","payType":"Fixed Pay","calculationType":"Fixed Amount","value":"2000","formula":"","baseComponent":"","taxable":true,"ctc":true,"proRata":true,"fbp":false,"restrictFbp":false,"epf":"Never","esi":true,"recurring":true,"scheduled":false,"investmentType":"","correctionOf":"","active":true,"priority":"30"},{"id":104,"code":"STAT_BONUS","componentType":"Bonus","category":"Earning","name":"Statutory Bonus","payType":"Fixed Pay","calculationType":"Formula","value":"","formula":"ROUNDDOWN(BASIC * 8.33%)","baseComponent":"BASIC","taxable":true,"ctc":true,"proRata":true,"fbp":false,"restrictFbp":false,"epf":"Never","esi":true,"recurring":true,"scheduled":false,"investmentType":"","correctionOf":"","active":true,"priority":"40"},{"id":105,"code":"MED_ALLOW","componentType":"Medical Allowance","category":"Earning","name":"Medical Allowance","payType":"Fixed Pay","calculationType":"Fixed Amount","value":"1250","formula":"","baseComponent":"","taxable":true,"ctc":true,"proRata":true,"fbp":false,"restrictFbp":false,"epf":"Never","esi":true,"recurring":true,"scheduled":false,"investmentType":"","correctionOf":"","active":true,"priority":"50"},{"id":106,"code":"OTHER_ALLOW","componentType":"Custom Allowance","category":"Earning","name":"Other Allowance","payType":"Fixed Pay","calculationType":"Residual / Balancing","value":"","formula":"GROSS - SUM(Fixed Earnings)","baseComponent":"GROSS","taxable":true,"ctc":true,"proRata":true,"fbp":false,"restrictFbp":false,"epf":"Never","esi":true,"recurring":true,"scheduled":false,"investmentType":"","correctionOf":"","active":true,"priority":"60"},{"id":107,"code":"LAPTOP_ALLOW","componentType":"Custom Allowance","category":"Earning","name":"Laptop Allowance","payType":"Fixed Pay","calculationType":"Fixed Amount","value":"2000","formula":"","baseComponent":"","taxable":true,"ctc":true,"proRata":true,"fbp":false,"restrictFbp":false,"epf":"Never","esi":true,"recurring":true,"scheduled":false,"investmentType":"","correctionOf":"","active":true,"priority":"70"},{"id":108,"code":"TA_DA","componentType":"Custom Allowance","category":"Earning","name":"TA/DA","payType":"Variable Pay","calculationType":"Manual / Variable","value":"","formula":"","baseComponent":"","taxable":true,"ctc":false,"proRata":true,"fbp":false,"restrictFbp":false,"epf":"Never","esi":true,"recurring":false,"scheduled":true,"investmentType":"","correctionOf":"","active":true,"priority":"80"},{"id":109,"code":"PF","componentType":"Provident Fund","category":"Deduction","name":"Provident Fund","payType":"Fixed Pay","calculationType":"Formula","value":"","formula":"MIN(BASIC, 15000) * 12%","baseComponent":"BASIC","taxable":false,"ctc":true,"proRata":true,"fbp":false,"restrictFbp":false,"epf":"Never","esi":false,"recurring":true,"scheduled":false,"investmentType":"","correctionOf":"","active":true,"priority":"110"}]';

SET @salaryStructures = '[{"id":201,"clientId":"1:Acme Technologies","name":"Acme Default CTC","annualCtc":"900000","lines":[{"componentId":"101","value":"GROSS * 50%"},{"componentId":"102","value":"BASIC * 40%"},{"componentId":"103","value":"2000"},{"componentId":"104","value":"ROUNDDOWN(BASIC * 8.33%)"},{"componentId":"105","value":"1250"},{"componentId":"106","value":"GROSS - SUM(Fixed Earnings)"},{"componentId":"107","value":"2000"},{"componentId":"108","value":""},{"componentId":"109","value":"MIN(BASIC,15000)*12%"}],"active":true}]';

INSERT INTO PayrollSetups (SetupJson)
SELECT JSON_OBJECT('salaryComponents', JSON_EXTRACT(@salaryComponents, '$'), 'salaryStructures', JSON_EXTRACT(@salaryStructures, '$'))
WHERE NOT EXISTS (SELECT 1 FROM PayrollSetups);

UPDATE PayrollSetups
SET SetupJson = JSON_SET(
  CASE WHEN JSON_VALID(SetupJson) THEN SetupJson ELSE JSON_OBJECT() END,
  '$.salaryComponents', JSON_EXTRACT(@salaryComponents, '$'),
  '$.salaryStructures', JSON_EXTRACT(@salaryStructures, '$')
);
